WHERE mar.del_flag = '0'

    AND mar.rule_name LIKE CONCAT('%', #{ruleName}, '%')


    AND mar.alarm_type = #{alarmType}


    AND mar.alarm_level = #{alarmLevel}


    AND mar.scope_type = #{scopeType}


    AND mar.enabled = #{enabled}

ORDER BY mar.create_time DESC, mar.id DESC

