rule_name = #{ruleName}, alarm_type = #{alarmType}, alarm_level = #{alarmLevel}, compare_operator = #{compareOperator}, threshold_value = #{thresholdValue}, scope_type = #{scopeType}, server_id = #{serverId}, silent_minutes = #{silentMinutes}, enabled = #{enabled}, remark = #{remark}, update_by = #{updateBy}, update_time = NOW()
